import { useEffect, useRef, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import useAuth from '../hooks/useAuth';
import useChat from '../hooks/useChatContext';
import useActions from '../hooks/useActions';
import ChatInput from '../components/ChatInput';
import MessageList from '../components/MessageList';
import './Chat.css';

const CAROUSEL_QUESTIONS = [
    "What makes a good date?",
    "Why do I get ghosted after the second date?",
    "Do you need looks for dating?",
    "Should I text her?",
    "How to get out of the friend zone",
];

function QuestionCarousel() {
    const [index, setIndex] = useState(0);
    const [fading, setFading] = useState(false);

    useEffect(() => {
        const interval = setInterval(() => {
            setFading(true);
            setTimeout(() => {
                setIndex(prev => (prev + 1) % CAROUSEL_QUESTIONS.length);
                setFading(false);
            }, 400);
        }, 3000);
        return () => clearInterval(interval);
    }, []);

    return (
        <div className="chat-empty">
            <h1 className="carousel-brand">InTension</h1>
            <p className={`carousel-question ${fading ? 'fade-out' : 'fade-in'}`}>
                {CAROUSEL_QUESTIONS[index]}
            </p>
        </div>
    );
}

export default function ChatPage() {
    const auth = useAuth();
    const navigate = useNavigate();
    const chat = useChat();
    const { createAction } = useActions();
    const scrollRef = useRef(null);

    useEffect(() => {
        if (scrollRef.current) {
            scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
        }
    }, [chat.messages, chat.busy]);

    return (
        <div className="chat-app">
            <header className="chat-topbar">
                <div className="chat-topbar-brand">
                    <span className="chat-topbar-dot" />
                    Intension
                </div>
                <div className="chat-topbar-right">
                    <button className="chat-topbar-nav" onClick={() => navigate('/actions')}>
                        Actions
                    </button>
                    <button className="chat-topbar-nav" onClick={() => navigate('/settings')}>
                        Settings
                    </button>
                    <button className="chat-topbar-signout" onClick={() => { chat.reset(); auth.signOut(); }}>
                        Sign out
                    </button>
                </div>
            </header>

            <div className="chat-thread" ref={scrollRef}>
                {chat.messages.length === 0 ? (
                    <QuestionCarousel />
                ) : (
                    <MessageList
                        messages={chat.messages}
                        busy={chat.busy}
                        onAcceptAction={createAction}
                    />
                )}
            </div>

            <div className="chat-input-area">
                <div className="chat-input-wrap">
                    <ChatInput
                        onSend={chat.send}
                        disabled={chat.busy}
                        placeholder={chat.messages.length === 0 ? "Start typing..." : "Reply..."}
                    />
                </div>
            </div>
        </div>
    );
}
