import { useState, useRef, useCallback } from 'react';
import './ChatInput.css';

function fileToBase64(file) {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = () => {
            const base64 = reader.result.split(',')[1];
            resolve({ data: base64, media_type: file.type, name: file.name, preview: reader.result });
        };
        reader.onerror = reject;
        reader.readAsDataURL(file);
    });
}

export default function ChatInput({ onSend, disabled, placeholder = "Start typing..." }) {
    const [value, setValue] = useState('');
    const [images, setImages] = useState([]);
    const textareaRef = useRef(null);
    const fileInputRef = useRef(null);

    const autosize = useCallback(() => {
        const el = textareaRef.current;
        if (!el) return;
        el.style.height = 'auto';
        el.style.height = Math.min(el.scrollHeight, 200) + 'px';
    }, []);

    const handleSubmit = (e) => {
        e.preventDefault();
        if ((!value.trim() && images.length === 0) || disabled) return;
        const imgPayload = images.map(i => ({ data: i.data, media_type: i.media_type }));
        onSend(value, imgPayload.length > 0 ? imgPayload : null);
        setValue('');
        setImages([]);
        if (textareaRef.current) {
            textareaRef.current.style.height = 'auto';
        }
    };

    const handleKeyDown = (e) => {
        if (e.key === 'Enter' && !e.shiftKey) {
            e.preventDefault();
            handleSubmit(e);
        }
    };

    const handleFileChange = async (e) => {
        const files = Array.from(e.target.files || []);
        if (files.length === 0) return;
        const allowed = ['image/png', 'image/jpeg', 'image/gif', 'image/webp'];
        const valid = files.filter(f => allowed.includes(f.type));
        const toAdd = valid.slice(0, Math.max(0, 5 - images.length));
        const converted = await Promise.all(toAdd.map(fileToBase64));
        setImages(prev => [...prev, ...converted]);
        if (fileInputRef.current) fileInputRef.current.value = '';
    };

    const removeImage = (idx) => {
        setImages(prev => prev.filter((_, i) => i !== idx));
    };

    const handlePaste = async (e) => {
        const items = Array.from(e.clipboardData?.items || []);
        const imageItems = items.filter(i => i.type.startsWith('image/'));
        if (imageItems.length === 0) return;
        e.preventDefault();
        const files = imageItems.map(i => i.getAsFile()).filter(Boolean);
        const toAdd = files.slice(0, Math.max(0, 5 - images.length));
        const converted = await Promise.all(toAdd.map(fileToBase64));
        setImages(prev => [...prev, ...converted]);
    };

    return (
        <form className="input-box" onSubmit={handleSubmit}>
            {images.length > 0 && (
                <div className="input-previews">
                    {images.map((img, i) => (
                        <div key={i} className="input-preview">
                            <img src={img.preview} alt="" />
                            <button type="button" className="input-preview-remove" onClick={() => removeImage(i)}>
                                &times;
                            </button>
                        </div>
                    ))}
                </div>
            )}
            <div className="input-row">
                <button
                    type="button"
                    className="attach-btn"
                    onClick={() => fileInputRef.current?.click()}
                    disabled={disabled || images.length >= 5}
                    title="Attach image"
                >
                    <svg viewBox="0 0 24 24"><path d="M21.44 11.05l-9.19 9.19a6 6 0 0 1-8.49-8.49l9.19-9.19a4 4 0 0 1 5.66 5.66l-9.2 9.19a2 2 0 0 1-2.83-2.83l8.49-8.48" /></svg>
                </button>
                <input
                    ref={fileInputRef}
                    type="file"
                    accept="image/png,image/jpeg,image/gif,image/webp"
                    multiple
                    style={{ display: 'none' }}
                    onChange={handleFileChange}
                />
                <textarea
                    ref={textareaRef}
                    className="chat-input"
                    placeholder={placeholder}
                    rows={1}
                    value={value}
                    onChange={(e) => { setValue(e.target.value); autosize(); }}
                    onKeyDown={handleKeyDown}
                    onPaste={handlePaste}
                    autoComplete="off"
                />
                <button type="submit" className="send-btn" disabled={disabled || (!value.trim() && images.length === 0)}>
                    <svg viewBox="0 0 24 24"><path d="M5 12h14M13 5l7 7-7 7" /></svg>
                </button>
            </div>
        </form>
    );
}
