import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider } from './hooks/useAuth';
import { ChatProvider } from './hooks/useChatContext';
import useAuth from './hooks/useAuth';
import SplashPage from './pages/Splash';
import AuthPage from './pages/Auth';
import ChatPage from './pages/Chat';
import ActionsPage from './pages/Actions';
import SettingsPage from './pages/Settings';
import './styles/variables.css';
import './App.css';

function AppRoutes() {
    const auth = useAuth();

    if (auth?.loading) {
        return <div className="app-loading" />;
    }

    const isAuthed = !!auth?.user;

    return (
        <Routes>
            <Route path="/" element={isAuthed ? <ChatPage /> : <SplashPage />} />
            <Route path="/auth" element={isAuthed ? <Navigate to="/" /> : <AuthPage />} />
            <Route path="/actions" element={isAuthed ? <ActionsPage /> : <Navigate to="/auth" />} />
            <Route path="/settings" element={isAuthed ? <SettingsPage /> : <Navigate to="/auth" />} />
        </Routes>
    );
}

export default function App() {
    return (
        <BrowserRouter>
            <AuthProvider>
                <ChatProvider>
                    <AppRoutes />
                </ChatProvider>
            </AuthProvider>
        </BrowserRouter>
    );
}
