import { createContext, useContext, useState, useCallback, useRef } from 'react';
import useAuth from './useAuth';

const API_URL = process.env.REACT_APP_API_URL || "https://5xg0tfvwd2.execute-api.us-west-2.amazonaws.com/prod/api/chat";

const ChatContext = createContext(null);

export function ChatProvider({ children }) {
    const auth = useAuth();
    const [messages, setMessages] = useState([]);
    const [busy, setBusy] = useState(false);
    const lastActivityRef = useRef(Date.now());

    const send = useCallback(async (text, images = null) => {
        text = (text || '').trim();
        if (!text && (!images || images.length === 0)) return;
        if (busy) return;

        lastActivityRef.current = Date.now();

        // Build previews for display
        const userMsg = { role: "user", content: text };
        if (images && images.length > 0) {
            userMsg.images = images.map(img => ({
                preview: `data:${img.media_type};base64,${img.data}`,
            }));
        }
        setMessages(prev => [...prev, userMsg]);
        setBusy(true);

        try {
            const headers = { "Content-Type": "application/json" };
            const token = await auth?.getIdToken();
            if (token) {
                headers["Authorization"] = `Bearer ${token}`;
            }

            const payload = { message: text };
            if (images && images.length > 0) {
                payload.images = images;
            }

            const res = await fetch(API_URL, {
                method: "POST",
                headers,
                body: JSON.stringify(payload),
            });

            if (res.status === 429) {
                setMessages(prev => [...prev, { role: "error", content: "Rate limit reached. Try again in a bit." }]);
            } else if (!res.ok) {
                let errText = "Please try again.";
                try {
                    const j = await res.json();
                    if (j.error) errText = j.error;
                } catch (_) {}
                setMessages(prev => [...prev, { role: "error", content: "Something went wrong. " + errText }]);
            } else {
                const data = await res.json();
                const reply = data.reply || "(no reply)";
                const assistantMsg = { role: "assistant", content: reply };
                if (data.proposed_action) {
                    assistantMsg.proposedAction = data.proposed_action;
                    assistantMsg.estimatedMinutes = data.estimated_minutes || null;
                }
                setMessages(prev => [...prev, assistantMsg]);
            }
        } catch (err) {
            setMessages(prev => [...prev, { role: "error", content: "Couldn't reach the server. Check your connection." }]);
        } finally {
            setBusy(false);
        }
    }, [busy, auth]);

    const reset = useCallback(() => {
        setMessages([]);
    }, []);

    return (
        <ChatContext.Provider value={{ messages, busy, send, reset }}>
            {children}
        </ChatContext.Provider>
    );
}

export default function useChat() {
    return useContext(ChatContext);
}
